#include <iostream>
#include <vector>
#include <string>
using namespace std;

#define MOD 7051954ll

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin >> T;

    while (T--) {
        int N, L, A, B;
        cin >> N >> L >> A >> B;
        string mcq;
        cin >> mcq;

        vector<int> next_plus(N);
        vector<int> next_minus(N);
        vector<int> plus_cnt(N);
        vector<int> minus_cnt(N);

        int np = -1, nm = -1;
        int cp = 0, cm = 0;

        for (int i = N - 1; i >= 0; --i) {
            char cur_char = mcq[i];
            if (cur_char == '+') {
                np = i;
                cp++;
            } else {
                nm = i;
                cm++;
            }
            next_plus[i] = np;
            next_minus[i] = nm;
            plus_cnt[i] = cp;
            minus_cnt[i] = cm;
        }

        int farthest_right = min(A + plus_cnt[0], L);
        int farthest_left = max(A - minus_cnt[0], 0);

        if (B < farthest_left || B > farthest_right) {
            cout << 0 << endl;
            continue;
        }

        vector<vector<int>> dp(farthest_right - farthest_left + 1, vector<int>(N + 1, 0));

        dp[B - farthest_left][N] = 1;

        for (int command_start = N - 1; command_start >= 0; --command_start) {
            for (int curposition = farthest_left; curposition <= farthest_right; ++curposition) {
                int cur_ind = curposition - farthest_left;
                int np = next_plus[command_start];
                int nm = next_minus[command_start];

                if (np != -1 && curposition + 1 <= farthest_right) {
                    dp[cur_ind][command_start] += dp[cur_ind + 1][np + 1];
                    dp[cur_ind][command_start] %= MOD;
                }

                if (nm != -1 && curposition - 1 >= farthest_left) {
                    dp[cur_ind][command_start] += dp[cur_ind - 1][nm + 1];
                    dp[cur_ind][command_start] %= MOD;
                }

                if (curposition == B) {
                    dp[cur_ind][command_start]++;
                    dp[cur_ind][command_start] %= MOD;
                }
            }
        }

        cout << dp[A - farthest_left][0] << endl;
    }

    return 0;
}
